const express = require('express');
const app = express();

// Load plugins from configuration files or environment variables
const plugins = [];
// Assume you have a function loadPlugins(path, callback) that loads plugins from specified path and calls the callback with loaded plugins.
loadPlugins('./plugins', (loadedPlugins) => {
  plugins.push(...loadedPlugins); // spread operator to merge arrays
});

app.use((req, res, next) => {
  let handleRequest = next;

  // Execute plugins middleware in the order they were loaded
  for (const plugin of plugins) {
    if (plugin.preRequest) {
      handleRequest = (req, res, next) => plugin.preRequest(req, res, next);
    }
    if (plugin.requestHandler) {
      handleRequest = plugin.requestHandler;
    }
  }

  // Call the actual request handler after executing all plugins
  handleRequest(req, res, () => {
    for (const plugin of plugins.reverse()) {
      if (plugin.postRequest) {
        plugin.postRequest(req, res);
      }
    }
    res.send('Done');
  });
});

app.listen(3000, () => console.log('API Gateway listening on port 3000'));